mapper.select:
select id, code, name, description
from roles
where id = #{id}

select count(1)
from roles
where code = #{code}

    and id != #{excludeId}

select id, module_code, module_name, icon, sort_order, status
from sys_modules
where id = #{id}

select count(1)
from sys_modules
where module_code = #{moduleCode}

    and id != #{excludeId}

select m.id, m.module_id, sm.module_code, sm.module_name, sm.icon as module_icon, sm.sort_order as module_sort_order, m.parent_id, m.menu_code, m.menu_name, m.route_path, m.component_key, m.icon, m.sort_order, m.status from sys_menus m inner join sys_modules sm on sm.id = m.module_id
( m.menu_code like concat('%', #{keyword}, '%') or m.menu_name like concat('%', #{keyword}, '%') or m.route_path like concat('%', #{keyword}, '%') )
and m.module_id = #{moduleId}
and m.parent_id = #{parentId}
order by sm.sort_order asc, sm.id asc, m.sort_order asc, m.id asc

select count(1)
from sys_menus
where menu_code = #{menuCode}

    and id != #{excludeId}

mapper.insert:
insert into sys_menus(
    module_id, parent_id, menu_code, menu_name, route_path, component_key, icon, sort_order, status, created_at, updated_at
)
values(
    #{moduleId}, #{parentId}, #{menuCode}, #{menuName}, #{routePath}, #{componentKey}, #{icon}, #{sortOrder}, #{status}, now(), now()
)

mapper.select:
select p.id, p.permission_code, p.permission_name, p.permission_type, p.module_id, sm.module_code, sm.module_name, p.menu_id, m.menu_code, m.menu_name, p.status, p.built_in, p.remark from sys_permissions p inner join sys_modules sm on sm.id = p.module_id left join sys_menus m on m.id = p.menu_id
( p.permission_code like concat('%', #{keyword}, '%') or p.permission_name like concat('%', #{keyword}, '%') )
and p.module_id = #{moduleId}
and p.menu_id = #{menuId}
and p.permission_type = #{permissionType}
order by sm.sort_order asc, p.permission_type asc, p.id asc

select count(1)
from sys_permissions
where permission_code = #{permissionCode}

    and id != #{excludeId}

mapper.insert:
insert into sys_permissions(
    permission_code, permission_name, permission_type, module_id, menu_id, status, built_in, remark, created_at, updated_at
)
values(
    #{permissionCode}, #{permissionName}, #{permissionType}, #{moduleId}, #{menuId}, #{status}, #{builtIn}, #{remark}, now(), now()
)

mapper.select:
select b.id, b.permission_id, p.permission_code, p.permission_name, b.http_method, b.path_pattern, b.controller_class, b.status from sys_api_permission_bindings b inner join sys_permissions p on p.id = b.permission_id
( p.permission_code like concat('%', #{keyword}, '%') or p.permission_name like concat('%', #{keyword}, '%') or b.path_pattern like concat('%', #{keyword}, '%') or b.controller_class like concat('%', #{keyword}, '%') )
and b.http_method = #{httpMethod}
and b.permission_id = #{permissionId}
order by b.id asc

select count(1)
from sys_api_permission_bindings
where http_method = #{httpMethod}
  and path_pattern = #{pathPattern}

    and id != #{excludeId}

mapper.insert:
insert into sys_api_permission_bindings(
    permission_id, http_method, path_pattern, controller_class, status, created_at, updated_at
)
values(
    #{permissionId}, #{httpMethod}, #{pathPattern}, #{controllerClass}, #{status}, now(), now()
)
